window.__QUIZ_DATA__=[{"id":"objective>Biology>2024>1","subject":"Biology","year":"2024","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Which of the following organisms contains chlorophyll in its cells?","images":[],"options":{"A":"Caterpillar","B":"Paramecium","C":"Euglena","D":"Grasshopper"},"answer":"C","explanation":"Euglena is a type of protist that contains chlorophyll and can perform photosynthesis, allowing it to produce its own food using light energy.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2024>2","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Species are groups of organisms that","images":[],"options":{"A":"are of different origins and are always found together","B":"are of common origin but cannot interbreed freely","C":"have similar features and can interbreed freely","D":"resemble each other and occupy different niches"},"answer":"C","explanation":"A species is defined as a group of organisms that share common characteristics and can interbreed under natural conditions to produce fertile offspring. Members of the same species generally have similar features and genetic makeup.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>3","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"A plant with short, vertical underground stem is a","images":[],"options":{"A":"bulb","B":"corm","C":"rhizome","D":"tuber"},"answer":"B","explanation":"Corm: A corm is a short, vertical underground stem that stores nutrients. It is a swollen, solid, underground stem that grows vertically and is found in plants like crocuses and taro.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2024>4","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The diagram below is an illustration of a reproductive process in an organism. Study it and answer the question      The type of reproduction illustrated is","images":["data:image/png;base64,"],"options":{"A":"budding","B":"binary fission","C":"grafting","D":"vegetative propagation"},"answer":"B","explanation":"Binary fission is a process of asexual reproduction in unicellular organisms in which a single cell(parent) divides into two equal parts by mitosis to produce two new daughter cells.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>5","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The diagram below is an illustration of a reproductive process in an organism. Study it and answer the question    The illustrated organism is capable of reproducing by","images":["data:image/png;base64,"],"options":{"A":"sexual means only","B":"asexual means only","C":"vegetative propagation only","D":"sexual and asexual means"},"answer":"D","explanation":"The organism in the diagram is paramecium. Paramecium reproduces in two ways: These are asexual reproduction (binary fission) and sexual reproduction (conjugation)","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>6","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST","question":"Which of the following organisms consists of unicellular cells joined to form a filament?","images":[],"options":{"A":"Amoeba","B":"Spirogyra","C":"Euglena","D":"Clamydomonas"},"answer":"B","explanation":"Spirogyra is a filamentous green algae consisting of long chains of unicellular cells. Each cell in the filament has chloroplasts arranged in a spiral pattern, which gives the algae its name.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2024>7","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"The structure in the cell that controls the movement of substances in and out of the cell is the","images":[],"options":{"A":"cytoplasmic membrane","B":"nuclear membrane","C":"protoplasm","D":"endoplasm"},"answer":"A","explanation":"Cytoplasmic membrane (or plasma membrane): This is a selective barrier that regulates the movement of substances into and out of the cell. It maintains the cell's internal environment by controlling the flow of ions, nutrients, and waste products.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>8","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : CELL AND ITS ENVIRONMENT","question":"The bursting of a red blood cell placed in a hypotonic solution is called","images":[],"options":{"A":"crenation","B":"haemolysis","C":"plasmolysis","D":"cytolysis"},"answer":"B","explanation":"Haemolysis refers to the rupture or destruction of red blood cells, often occurring when they are placed in a hypotonic solution where water enters the cells, causing them to swell and burst.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>9","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : CELL AND ITS ENVIRONMENT","question":"The function of the root hair in plants is to","images":[],"options":{"A":"absorb soil water by the process of osmosis","B":"excrete water and mineral salts by simple diffusion","C":"purify the soil for the plant","D":"translocate manufactured food"},"answer":"A","explanation":"Absorb soil water by the process of osmosis: Root hairs increase the surface area for water and nutrient absorption from the soil. They help in the uptake of water through osmosis and minerals through active transport.","marks":"1","difficulty":"3"},{"id":"objective>Biology>2024>10","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM","question":"If a germinating seed is attached horizontally to a revolving klinostat, what would be the effect on the seedling after three days? The","images":[],"options":{"A":"plumule will curve vertically upward while the radicle will not show any curvature","B":"radicle will curve towards the ground while the plumule will not show any curvature","C":"plumule and radicle will not show any curvature","D":"plumule will curve vertically. upwards while the radicle will curve towards the ground"},"answer":"C","explanation":"A klinostat is a device that rotates the seedling to counteract the effects of gravity. This rotation ensures that the seedling experiences an even distribution of gravitational forces. As a result, both the plumule (the part of the seedling that develops into the shoot) and the radicle (the part that develops into the root) will grow straight without showing the typical curvatures that occur in response to gravity.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>11","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"The lumbar vertebra differs from the thoracic vertebra because it possesses a","images":[],"options":{"A":"longer neural spine","B":"wider neural canal","C":"thicker centrum","D":"shorter transverse process"},"answer":"C","explanation":"Thicker centrum: Lumbar vertebrae have a thicker and more robust centrum (the body of the vertebra) compared to thoracic vertebrae. This is because the lumbar region supports more weight from the upper body and needs a stronger base.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>12","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"Which of the following blood vessels carries oxygenated blood into the heart?","images":[],"options":{"A":"Pulmonary artery","B":"Anterior vena cava","C":"Pulmonary vein","D":"Posterior vena cava"},"answer":"C","explanation":"The pulmonary vein carries oxygenated blood from the lungs to the left atrium of the heart.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2024>13","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"Filtrates in the Bowman's capsule contain vitamins because","images":[],"options":{"A":"they have low molecular weight","B":"most of them are fat soluble","C":"they cannot be reabsorbed into the blood","D":"little amount is required by the blood"},"answer":"A","explanation":"Many vitamins, especially water-soluble ones like the B-complex vitamins and vitamin C, have relatively low molecular weights. This allows them to pass through the filtration barrier into the Bowman's capsule.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>14","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"The structures that contain grey matter and white matter are found in the","images":[],"options":{"A":"reproductive system","B":"nervous system","C":"respiratory system","D":"digestive system"},"answer":"B","explanation":"Grey Matter and White Matter:    Grey Matter: This consists primarily of neuronal cell bodies, dendrites, and unmyelinated axons. It is involved in processing and interpreting information in the brain and spinal cord.  White Matter: This consists mainly of myelinated axons, which form the communication pathways between different parts of the grey matter and between the grey matter and other parts of the nervous system.  Locations in the Nervous System:    In the brain, grey matter is found in regions such as the cerebral cortex and the basal ganglia, while white matter is found in the deeper tissues of the brain, underlying the grey matter.  In the spinal cord, grey matter is located in the central part (forming an H-shaped structure), while white matter surrounds it on the outside.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2024>15","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"The diagram below is an illustration of a sense organ in humans. Study it and answer the question.      The part that protects the organ is labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"B","explanation":"II. The parts that protect the eye are the upper and lower eyelids. These structures help to shield the eye from debris, excessive light, and injury, as well as to keep it moist.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>16","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"The diagram below is an illustration of a sense organ in humans. Study it and answer the question.    The part labelled III is the","images":["data:image/png;base64,"],"options":{"A":"iris","B":"pupil","C":"sclera","D":"cornea"},"answer":"B","explanation":"Pupil: The black circular opening in the center of the iris that allows light to enter the eye.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>17","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The diagram below is an illustration of two plants P and Q. Arrows I, II and III illustrate the transfer of pollen grains among flowers of plants P and Q. Study it and answer the question      The types of pollination illustrated as I, II and III,respectively are","images":["data:image/png;base64,"],"options":{"A":"cross,self and cross","B":"self,self and cross","C":"self,cross and self","D":"self,cross and cross"},"answer":"D","explanation":"Arrow I represents self-pollination within plant P.  Arrow II represents cross-pollination from plant P to plant Q.  Arrow III represents cross-pollination from plant Q to plant P.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>18","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The diagram below is an illustration of two plants P and Q. Arrows I, II and III illustrate the transfer of pollen grains among flowers of plants P and Q. Study it and answer the question    The condition necessary for reproduction to occur between plants P and Q after pollination is that plants P and Q should be","images":["data:image/png;base64,"],"options":{"A":"of the same species","B":"brightly coloured","C":"well scented","D":"of different species"},"answer":"A","explanation":"The condition necessary for reproduction to occur between plants P and Q after pollination is that plants P and Q should be of the same species.  Of the same species: For successful reproduction and fertilization to occur, the pollen from one plant must be compatible with the ovules of the other plant. This compatibility is ensured if both plants are of the same species. The genetic material must match for fertilization to lead to viable seeds.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>19","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The diagram below illustrates a dry dehiscent fruit. Use it to answer the question      The agent of dispersal of the fruit is","images":["data:image/png;base64,"],"options":{"A":"animal","B":"explosive mechanism","C":"water","D":"wind"},"answer":"D","explanation":"Tridax, commonly known as Tridax daisy (Tridax procumbens), has seeds that are adapted for wind dispersal. The seeds are typically lightweight and equipped with structures like pappi (hair-like appendages) that allow them to be carried by the wind.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2024>20","subject":"Biology","year":"2024","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The diagram below illustrates a dry dehiscent fruit. Use it to answer the question    The parachute-like tuft of hairs developed from the","images":["data:image/png;base64,"],"options":{"A":"pedicel","B":"petals","C":"receptacle","D":"sepals"},"answer":"D","explanation":"The parachute-like tuft of hairs found on some seeds, such as those of Tridax and other members of the Asteraceae family, is typically developed from the sepals.    In these plants, the sepals transform into a structure known as a pappus, which is a modified calyx that aids in wind dispersal. The pappus consists of fine hairs that create a parachute-like structure, enabling the seeds to be carried away by the wind.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2024>21","subject":"Biology","year":"2024","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Which of the following events does not occur in the light reaction stage of photosynthesis?","images":[],"options":{"A":"Chlorophyll absorbs sunlight","B":"Carbon (IV) oxide combines with hydrogen","C":"Photolysis of water occurs","D":"Hydroxyl ions are produced"},"answer":"B","explanation":"The light reaction stage of photosynthesis, also known as the light-dependent reactions, primarily involves the absorption of light by chlorophyll, the photolysis (splitting) of water, and the production of energy-rich molecules (ATP and NADPH). This event occurs during the Calvin cycle, also known as the light-independent reactions or the dark reactions. In the Calvin cycle, carbon dioxide is fixed into organic molecules using the ATP and NADPH produced during the light reactions.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>22","subject":"Biology","year":"2024","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"The rate of photosynthesis decreases in a wilted herbaceous plant because the","images":[],"options":{"A":"enzymes in the leaf were denatured","B":"chlorophyll in the leaves was not broken down","C":"amount of light reaching the plant was reduced","D":"amount of carbon dioxide entering the leaf decreased"},"answer":"D","explanation":"The rate of photosynthesis can decrease in a wilted herbaceous plant due to several factors, but the most relevant one is related to the availability of carbon dioxide. In a wilted plant, the stomata (pores on the leaf surface) often close to prevent further water loss. When the stomata close, the exchange of gases is restricted, reducing the amount of carbon dioxide that can enter the leaf.    Since carbon dioxide is a crucial reactant in the photosynthesis process, a decrease in its availability directly impacts the rate of photosynthesis.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>23","subject":"Biology","year":"2024","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"The element required for chlorophyll formation in plants is","images":[],"options":{"A":"iron","B":"calcium","C":"phosphorus","D":"sulphur"},"answer":"A","explanation":"The element required for chlorophyll formation in plants is iron. Iron is a crucial component of the enzyme systems involved in the synthesis of chlorophyll. It acts as a catalyst in the formation of chlorophyll and plays a vital role in the overall process of photosynthesis.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2024>24","subject":"Biology","year":"2024","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM","question":"The process of food digestion in mammals would","images":[],"options":{"A":"make energy immediately available to the body","B":"promote growth and repair of tissues","C":"provide sufficient food materials within the body","D":"render food substances soluble and absorbable"},"answer":"D","explanation":"The primary function of food digestion in mammals is to break down complex food substances into simpler, soluble forms that can be absorbed into the bloodstream and utilized by the body. This process involves mechanical and chemical breakdown of food in the digestive system, leading to the formation of nutrients that can be absorbed through the walls of the intestines.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>25","subject":"Biology","year":"2024","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Which of the following food substances would give a negative reaction with Benedict's reagent?","images":[],"options":{"A":"Fructose","B":"Glucose","C":"Galactose","D":"Sucrose"},"answer":"D","explanation":"Benedict's reagent is used to test for the presence of reducing sugars. Reducing sugars, such as fructose, glucose, and galactose, have free aldehyde or ketone groups that can reduce the copper(II) ions in Benedict's reagent to copper(I) oxide, resulting in a colour change.    Sucrose, however, is a non-reducing sugar. It is composed of glucose and fructose linked by a glycosidic bond, which prevents the free aldehyde or ketone group from reacting with Benedict's reagent. Therefore, sucrose would give a negative reaction with Benedict's reagent, meaning there would be no color change when sucrose is present.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2024>26","subject":"Biology","year":"2024","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE","question":"Sunlight is the major source of","images":[],"options":{"A":"vitamin D","B":"vitamin C","C":"vitamin B","D":"vitamin A"},"answer":"A","explanation":"Sunlight is the major source of vitamin D because exposure to ultraviolet (UV) rays from the sun triggers the synthesis of vitamin D in the skin. Specifically, UVB radiation converts 7-dehydrocholesterol in the skin to previtamin D3, which is then converted to vitamin D3 (cholecalciferol). This process is the primary natural method for humans to obtain vitamin D, which is essential for maintaining healthy bones and supporting the immune system.    Vitamins C, B, and A are obtained from dietary sources rather than being synthesized through exposure to sunlight.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>27","subject":"Biology","year":"2024","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Discouraging the use of poison to kill fish in a large water body is a way of","images":[],"options":{"A":"impoverishing the people","B":"conserving the fish species","C":"allowing the fittest organism to survive","D":"making the fish adapt to their environment"},"answer":"B","explanation":"Discouraging the use of poison to kill fish in a large water body is a conservation measure aimed at protecting fish species. Using poison can have detrimental effects on the aquatic ecosystem, including killing a wide range of organisms indiscriminately, disrupting the food chain, and contaminating the water. By preventing the use of poison, the natural populations of fish and other aquatic organisms can be preserved, ensuring the sustainability and health of the ecosystem.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>28","subject":"Biology","year":"2024","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE","question":"The pathway through which nutrients are replenished and circulated in an ecosystem is called a","images":[],"options":{"A":"cycle","B":"pyramid of energy","C":"pyramid of numbers","D":"food chain"},"answer":"A","explanation":"The pathway through which nutrients are replenished and circulated in an ecosystem is referred to as a cycle. This includes processes like the water cycle, carbon cycle, nitrogen cycle, and phosphorus cycle. These cycles ensure that essential nutrients are continuously recycled and made available to living organisms within the ecosystem.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>29","subject":"Biology","year":"2024","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"The illustration below is a food chain. Study it and answer the question.  Grasses \u2192Grasshoppers\u2192Lizards\u2192Hawks    Which of the following statements is not correct about the food chain? The number of","images":[],"options":{"A":"grasses eaten by grasshoppers is greater than the number of grasshoppers","B":"grasses eaten by grasshoppers is fewer than the number of grasshoppers","C":"grasshoppers eaten by lizards is greater than the number of lizards","D":"lizards eaten by hawks is greater than the number of hawks"},"answer":"B","explanation":"In a food chain, the number of organisms and the amount of biomass generally decrease as you move up trophic levels. This means that:    There are more grasses than grasshoppers because grasshoppers feed on grasses.  There are more grasshoppers than lizards because lizards feed on grasshoppers.  There are more lizards than hawks because hawks feed on lizards.  Therefore, the statement \"grasses eaten by grasshoppers is fewer than the number of grasshoppers\" is incorrect because there must be more grass (in terms of biomass and number) than grasshoppers to support their population.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>30","subject":"Biology","year":"2024","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"The illustration below is a food chain. Study it and answer the question.  Grasses \u2192Grasshoppers\u2192Lizards\u2192Hawks  If the individual species of organisms in the food chain are counted and arranged as a pyramid, the result would be a pyramid of","images":[],"options":{"A":"numbers","B":"energy","C":"biomass","D":"biomes"},"answer":"A","explanation":"A pyramid of numbers represents the number of individual organisms at each trophic level in a food chain. In the given food chain (Grasses \u2192 Grasshoppers \u2192 Lizards \u2192 Hawks), if you count the individuals and arrange them in a pyramid, you will have:    A large number of grasses at the base.  Fewer grasshoppers feeding on the grasses.  Even fewer lizards feeding on the grasshoppers.  The fewest hawks at the top feeding on the lizards.  This arrangement, based on the number of organisms at each trophic level, forms a pyramid of numbers.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>31","subject":"Biology","year":"2024","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"Which of the following gases is released during the decomposition of organic matter?","images":[],"options":{"A":"Carbon (II) oxide","B":"Sulphur (IV) oxide","C":"Hydrogen sulphide","D":"Nitrous oxide"},"answer":"C","explanation":"During the decomposition of organic matter, especially under anaerobic conditions (in the absence of oxygen), various gases are released as by-products. One of these gases is hydrogen sulphide (H\u2082S), which is produced by the action of bacteria breaking down proteins and other sulfur-containing compounds in the organic matter.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2024>32","subject":"Biology","year":"2024","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"The diagrams below are illustrations of organisms from different habitats. Study them and answer the question      The structures labelled I are for","images":["data:image/png;base64,"],"options":{"A":"camouflage","B":"chemical offence","C":"physical defence","D":"mimicry"},"answer":"C","explanation":"The structures labelled \"I\" in the illustration are spines or thorns on the plant. These structures serve as a form of physical defence to protect the plant from being eaten by herbivores. The spines can deter animals from approaching or consuming the plant by causing physical discomfort or injury.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>33","subject":"Biology","year":"2024","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"The diagrams below are illustrations of organisms from different habitats. Study them and answer the question    Habitats of the organisms respectively, are","images":["data:image/png;base64,"],"options":{"A":"river and stream","B":"rainforest and stream","C":"pond and leaf litter","D":"garden and desert"},"answer":"D","explanation":"The organism on the left is a snail, which is commonly found in gardens where it feeds on plants.  The organism on the right appears to be a cactus, which is typically found in desert environments. Cacti have spines as an adaptation to reduce water loss and protect against herbivores.  Thus, the respective habitats of the organisms illustrated are likely a garden for the snail and a desert for the cactus.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2024>34","subject":"Biology","year":"2024","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT","question":"An environmental problem caused by Sulphur (IV) oxide is","images":[],"options":{"A":"acid rain","B":"deforestation","C":"global warming","D":"erosion"},"answer":"A","explanation":"Sulphur (IV) oxide is a significant contributor to the formation of acid rain. When SO\u2082 is released into the atmosphere, it reacts with water vapor and other chemicals to form sulphuric acid (H\u2082SO\u2084). This sulfuric acid can then fall to the earth as acid rain, which can harm ecosystems, damage buildings, and negatively affect plant and animal life.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>35","subject":"Biology","year":"2024","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT","question":"The phenomenon by which a farmland that is left to fallow for several years develops into a forest is called","images":[],"options":{"A":"succession","B":"afforestation","C":"population","D":"colonization"},"answer":"A","explanation":"Succession is the process by which the structure of a biological community evolves over time. There are two main types of succession:    Primary succession occurs in lifeless areas where there is no soil, such as on a lava flow or a new sand dune.  Secondary succession occurs in areas where a disturbance (such as farming) has occurred, but soil and some organisms still exist.  When farmland is abandoned and left to fallow, secondary succession typically takes place. Over time, grasses and weeds first colonize the land, followed by shrubs and eventually trees, leading to the development of a forest.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>36","subject":"Biology","year":"2024","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT","question":"A farmer planted many seeds on a small piece of land. The plants that germinated are as shown below.    Which of the following effects would not be observed among the population of the plants?","images":["data:image/png;base64,"],"options":{"A":"Rise in disease condition","B":"Death","C":"Mutualistic relationship","D":"Competition"},"answer":"D","explanation":"Competition in plants refers to the interaction between plants where they vie for the same resources such as light, water, nutrients, and space. This competition can influence plant growth, survival, and reproduction, and it occurs both within a single species (intraspecific competition) and between different species (interspecific competition).","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>37","subject":"Biology","year":"2024","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"The bar chart below shows the data of sources of energy used for cooking in a community. Study it and answer the question      The source of energy that is mostly used in the community is","images":["data:image/png;base64,"],"options":{"A":"solar","B":"kerosene","C":"coal","D":"wind"},"answer":"B","explanation":"The source of energy that is mostly used in the community is kerosene. The bar chart shows six(6) number of households using kerosene which is the highest.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>38","subject":"Biology","year":"2024","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT","question":"The bar chart below shows the data of sources of energy used for cooking in a community. Study it and answer the question    The two sources of energy that would mostly lead to pollution in the community are","images":["data:image/png;base64,"],"options":{"A":"solar and kerosene","B":"coal and wind","C":"kerosene and coal","D":"solar and wind"},"answer":"C","explanation":"The two sources of energy that would mostly lead to pollution in the community are kerosene and coal. Kerosene is a liquid fossil fuel and Coal is a solid fossil fuel. Both kerosene and coal are significant sources of pollution, impacting air quality, human health, and the environment. Transitioning to cleaner energy sources, such as solar, wind, and hydroelectric power, can help reduce these negative impacts and promote a healthier and more sustainable community.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2024>39","subject":"Biology","year":"2024","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"An individual found a strange bird that is tagged as an endangered specie. What should the individual do?","images":[],"options":{"A":"Kill it","B":"Take it to an aquatic environment","C":"Return it to its natural habitat","D":"Sell it at a very high price"},"answer":"C","explanation":"Endangered species are protected by laws and regulations due to their risk of extinction. Returning the bird to its natural habitat ensures that it remains in the environment it is adapted to, which supports its survival and the overall ecosystem's health. If the exact location of its natural habitat is unknown, contacting local wildlife authorities or conservation organizations for guidance is advisable.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>40","subject":"Biology","year":"2024","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Which of the following traits is not inheritable? Ability to","images":[],"options":{"A":"taste P.T.C","B":"roll the tongue","C":"move the ear","D":"roll the eyeball"},"answer":"D","explanation":"Rolling the eyeball is not considered an inheritable trait. It is more related to voluntary muscle control and eye movement skills, which are learned rather than inherited.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>41","subject":"Biology","year":"2024","type":"Objective","topic":"APPLICATION OF VARIATIONS :","question":"Which of the following statements is correct about the ABO blood group system?","images":[],"options":{"A":"Antigens are located on the surface of white blood cells","B":"Antibodies are located in the blood plasma","C":"Antibodies are located on the surface of red blood cells","D":"Antigens are located in the blood plasma"},"answer":"B","explanation":"In the ABO blood group system:    Antigens are located on the surface of red blood cells. These antigens determine the blood type (A, B, AB, or O).  Antibodies are located in the blood plasma. These antibodies are specific to the antigens that are not present on the individual's red blood cells.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>42","subject":"Biology","year":"2024","type":"Objective","topic":"APPLICATION OF VARIATIONS :","question":"A woman with blood group A gives birth to a child with blood group O. Which of the following blood groups cannot belong to the father?","images":[],"options":{"A":"B","B":"A","C":"AB","D":"O"},"answer":"C","explanation":"Blood group A can have the genotype AA or AO.  Blood group B can have the genotype BB or BO.  Blood group AB has the genotype AB.  Blood group O has the genotype OO.  For a child to have blood group O, they must inherit an O allele from each parent, resulting in the genotype OO. This means both parents must carry at least one O allele.  B \u2013 The father could be BO, contributing an O allele to the child.  A \u2013 The father could be AO, contributing an O allele to the child.  AB \u2013 The father has the genotype AB and cannot contribute an O allele.  O \u2013 The father has the genotype OO, contributing an O allele to the child.  The blood group that cannot belong to the father is:AB  The father must be able to contribute an O allele for the child to have the blood group O. Since an AB individual does not have an O allele to pass on, they cannot be the father.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>43","subject":"Biology","year":"2024","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"The diagram below is an illustration of the genetic cross between two parents. The parental gametes I,II,III and IV gave rise to the offspring below. Study it and answer the question      Gametes I, II, III and IV, respectively are","images":["data:image/png;base64,"],"options":{"A":"T,T,T and t","B":"T,t,t and t","C":"T,T,t and t","D":"T,t,T and t"},"answer":"B","explanation":"Gametes I, II, III and IV, respectively are T,t,t and t.","marks":"1","difficulty":"3"},{"id":"objective>Biology>2024>44","subject":"Biology","year":"2024","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"The diagram below is an illustration of the genetic cross between two parents. The parental gametes I,II,III and IV gave rise to the offspring below. Study it and answer the question    Which of the following statements is correct about the cross?","images":["data:image/png;base64,"],"options":{"A":"Both parents are heterozygous","B":"The male is not heterozygous","C":"The female is homozygous","D":"Both parents are homozygous"},"answer":"A","explanation":"The genetic cross is between a heterozygous individual (Tt) and a homozygous recessive individual (tt).","marks":"1","difficulty":"3"},{"id":"objective>Biology>2024>45","subject":"Biology","year":"2024","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"The physical appearance of an organism is described as its","images":[],"options":{"A":"phenotype","B":"genotype","C":"allele","D":"chromosome"},"answer":"A","explanation":"Phenotype refers to the observable characteristics or traits of an organism, such as its physical appearance, behavior, or biochemical properties. These traits result from the interaction of the organism's genotype (genetic makeup) with the environment.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2024>46","subject":"Biology","year":"2024","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Mutation leads to evolution because it","images":[],"options":{"A":"kills all organisms where it has occurred","B":"gives rise to offspring having same characteristics as the parents","C":"does not confer adaptability to the offspring","D":"gives rise to new individuals that differ from their parents"},"answer":"D","explanation":"Mutation is a change in the DNA sequence of an organism's genome. It can introduce new genetic variations by altering the genetic code, which can lead to new traits or characteristics in individuals. Mutations introduce genetic diversity by creating new alleles. This diversity is the raw material for evolution, as it can lead to new traits in individuals that may be subject to natural selection, driving evolutionary changes in populations over time.  Mutations are a fundamental source of genetic variation, which is essential for the process of evolution.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>47","subject":"Biology","year":"2024","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"The male and female gametes which bear genes for inheritance in plants are locat\u00e8d in the","images":[],"options":{"A":"anthers and petals","B":"sepals and petals","C":"stamens and pistils.","D":"stamens and petals"},"answer":"C","explanation":"Stamens (male reproductive parts): The stamen is the male part of a flower and consists of the anther and filament. The anther produces pollen, which contains the male gametes (sperm cells). These gametes are involved in fertilizing the ovules.    Pistils (female reproductive parts): The pistil is the female part of a flower and consists of the stigma, style, and ovary. The ovary contains the ovules, which are the female gametes (egg cells).    So, the male gametes are located in the anthers of the stamens, and the female gametes are located in the ovules within the ovary of the pistils. This is where the processes of pollination and fertilization occur, leading to the formation of seeds and the continuation of plant species.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2024>48","subject":"Biology","year":"2024","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"Which type of breeding is represented by industrial melanism in peppered moths?","images":[],"options":{"A":"Artificial selection","B":"Natural selection","C":"Inbreeding","D":"Outbreeding"},"answer":"B","explanation":"Industrial melanism refers to the darkening of the peppered moth (Biston betularia) populations in industrial areas due to pollution. Before the Industrial Revolution, the light-colored form of the moth was more common because it was better camouflaged against lichen-covered tree bark. However, as industrial pollution killed the lichens and darkened the tree bark with soot, the dark-colored (melanic) form of the moth became better camouflaged and thus had a survival advantage.    Natural selection is the process through which individuals with traits that are better suited to their environment have a higher chance of survival and reproduction. In the case of the peppered moths, the dark-colored variant had a selective advantage in polluted environments, leading to an increase in its frequency within the population.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>49","subject":"Biology","year":"2024","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"In a test, a student paired some scientists with their famous work as shown below. Use it to answer the question  Scientist---Famous work  I. Charles Darwin \u2192 preservation of some food with heat  II. Gregor Mendel \u2192 natural selection  III. Jean Baptiste \u2192 inheritance of Lamarck                    IV Louis Pasteur \u2192 independent assortment of genes    The scientists that are not correctly paired with their famous work are","images":[],"options":{"A":"I and II only","B":"II and III only","C":"I,II and IV","D":"II,III and IV"},"answer":"C","explanation":"Charles Darwin: Known for his work on natural selection. Darwin's theory of natural selection explains how species evolve over time through the preservation of advantageous traits.    Gregor Mendel: Known for his work on the inheritance of genes. Mendel's experiments with pea plants established the basic principles of heredity, including the concepts of dominant and recessive traits.    Jean-Baptiste Lamarck: Known for his theory of inheritance of acquired characteristics (often referred to as Lamarckism), which is a different idea from natural selection. Lamarck proposed that traits acquired during an organism's lifetime could be passed on to offspring.    Louis Pasteur: Known for his work on pasteurization, which involves the preservation of food and liquids by heat to kill harmful microbes. He is also famous for his experiments disproving spontaneous generation.  The scientists that are not correctly paired with their famous work are: I, II, and IV","marks":"1","difficulty":"2"},{"id":"objective>Biology>2024>50","subject":"Biology","year":"2024","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"In a test, a student paired some scientists with their famous work as shown below. Use it to answer the question  Scientist---Famous work  I. Charles Darwin \u2192 preservation of some food with heat  II. Gregor Mendel \u2192 natural selection  III. Jean Baptiste \u2192 inheritance of Lamarck                    IV Louis Pasteur \u2192 independent assortment of genes              Which of the scientists were involved in the study of evolution?","images":[],"options":{"A":"I and III","B":"II and III","C":"I,II and IV","D":"II,III and IV"},"answer":"A","explanation":"Charles Darwin: He is best known for his theory of natural selection, which is a fundamental concept in the study of evolution. Darwin's work laid the foundation for the modern understanding of how species evolve over time.  Jean-Baptiste Lamarck: He proposed an early theory of evolution known as Lamarckism, which suggested that organisms could pass on traits acquired during their lifetime to their offspring. Although his ideas were later replaced by Darwin's theory of natural selection, Lamarck was involved in early evolutionary theory.","marks":"1","difficulty":"2"}];